  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 4px;
  position: relative;
  overflow: hidden;
  opacity: 0;
  transform: translateY(30px);
  transition: all 0.6s cubic-bezier(0.16, 1, 0.3, 1);
}

.who-card.visible {
  opacity: 1;
  transform: translateY(0);
}

.who-card:nth-child(1) {
  transition-delay: 0s;
}

.who-card:nth-child(2) {
