  font-size: 1.2rem;
  font-weight: 700;
  margin-bottom: 1rem;
}

.who-body {
  font-size: 0.88rem;
  color: var(--gray);
  line-height: 1.7;
}

#about {
  background: var(--dark);
}

.about-layout {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 8rem;
