}

.about-text h2 {
  font-family: 'Syne', sans-serif;
  font-weight: 800;
  font-size: clamp(2rem, 3.5vw, 3rem);
  line-height: 1.1;
  margin-bottom: 2rem;
}

.about-text p {
  color: var(--gray);
  font-size: 0.95rem;
  line-height: 1.8;
  margin-bottom: 1.5rem;
}

.about-text .green-quote {
  border-left: 2px solid var(--green);
  padding-left: 1.5rem;
  margin: 2rem 0;
  font-size: 1.1rem;
  color: var(--white);
  line-height: 1.6;
  font-weight: 300;
  font-style: italic;
}

.values-list {
  display: flex;
  flex-direction: column;
  gap: 1.5rem;
}

.value-item {
  display: flex;
  gap: 1.5rem;
  align-items: flex-start;
  padding: 1.5rem;
  background: var(--card);
  border: 1px solid rgba(255, 255, 255, 0.05);
  border-radius: 3px;
  opacity: 0;
  transform: translateX(30px);
  transition: all 0.5s ease;
}

.value-item.visible {
  opacity: 1;
  transform: translateX(0);
}

.value-item:nth-child(1) {
  transition-delay: 0s;
}

.value-item:nth-child(2) {
  transition-delay: 0.12s;
}

.value-item:nth-child(3) {
  transition-delay: 0.24s;
}

.value-item:nth-child(4) {
  transition-delay: 0.36s;
}

.value-icon {
  color: var(--green);
  font-size: 1.2rem;
  flex-shrink: 0;
  margin-top: 2px;
}

.value-title {
  font-size: 0.9rem;
  font-weight: 600;
  color: var(--white);
  margin-bottom: 0.3rem;
}

.value-desc {
  font-size: 0.82rem;
  color: var(--gray);
  line-height: 1.5;
}

#cta-band {
  background: linear-gradient(135deg, #050e0a 0%, #081a10 50%, #050e0a 100%);
  border-top: 1px solid rgba(16, 185, 129, 0.15);
  border-bottom: 1px solid rgba(16, 185, 129, 0.15);
  padding: 8rem 4rem;
  text-align: center;
  position: relative;
  overflow: hidden;
}

.cta-bg {
  position: absolute;
  inset: 0;
  background: radial-gradient(ellipse 70% 70% at 50% 50%, rgba(16, 185, 129, 0.07) 0%, transparent 70%);
  pointer-events: none;
}

#cta-band h2 {
  font-family: 'Syne', sans-serif;
  font-weight: 800;
  font-size: clamp(2.5rem, 5vw, 5rem);
  line-height: 1;
  margin-bottom: 1.5rem;
  position: relative;
  z-index: 1;
}

#cta-band h2 em {
  color: var(--green);
  font-style: normal;
  display: block;
}

#cta-band p {
  color: var(--gray);
  font-size: 1rem;
  max-width: 480px;
  margin: 0 auto 3rem;
  position: relative;
  z-index: 1;
}

#cta-band .btn-primary {
  font-size: 0.9rem;
  padding: 1.2rem 2.8rem;
  position: relative;
  z-index: 1;
}

#contact {
  background: var(--black);
}

.contact-layout {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 8rem;
}

.contact-text h2 {
  font-family: 'Syne', sans-serif;
  font-weight: 800;
  font-size: clamp(2rem, 3.5vw, 3rem);
  line-height: 1.1;
  margin-bottom: 1.5rem;
}

.contact-text p {
  color: var(--gray);
  font-size: 0.95rem;
  line-height: 1.8;
  margin-bottom: 2.5rem;
}

.contact-details {
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.contact-item {
  display: flex;
  gap: 1rem;
  align-items: center;
  padding: 1.2rem 1.5rem;
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 3px;
  text-decoration: none;
  color: var(--gray);
  font-size: 0.9rem;
  transition: all 0.3s ease;
}

.contact-item:hover {
  border-color: rgba(16, 185, 129, 0.3);
  color: var(--white);
  background: rgba(16, 185, 129, 0.04);
}

.contact-item .ci-label {
  font-size: 0.7rem;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--green);
  display: block;
  margin-bottom: 0.2rem;
}

.contact-form {
  display: flex;
  flex-direction: column;
  gap: 1.2rem;
}

.form-group {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.form-label {
  font-size: 0.72rem;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--gray);
  font-weight: 500;
}

.form-input,
.form-select,
.form-textarea {
  background: var(--card);
  border: 1px solid rgba(255, 255, 255, 0.08);
  color: var(--white);
  padding: 0.9rem 1.1rem;
  border-radius: 2px;
  font-family: 'Outfit', sans-serif;
  font-size: 0.9rem;
  transition: border-color 0.3s ease, box-shadow 0.3s ease;
  outline: none;
  width: 100%;
}

.form-input:focus,
.form-select:focus,
.form-textarea:focus {
  border-color: rgba(16, 185, 129, 0.5);
  box-shadow: 0 0 0 3px rgba(16, 185, 129, 0.08);
}

.form-select option {
  background: var(--dark);
}

.form-textarea {
  resize: vertical;
  min-height: 100px;
}

.form-submit {
  background: var(--green);
  color: #000;
  border: none;
  padding: 1rem 2rem;
  font-family: 'Outfit', sans-serif;
  font-size: 0.85rem;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  border-radius: 2px;
  cursor: none;
  transition: all 0.3s ease;
}

.form-submit:hover {
  background: #0ea371;
  box-shadow: 0 8px 24px rgba(16, 185, 129, 0.3);
  transform: translateY(-1px);
}

footer {
  background: var(--dark);
  border-top: 1px solid rgba(255, 255, 255, 0.05);
  padding: 4rem;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.footer-brand {
  font-family: 'Syne', sans-serif;
  font-weight: 800;
  font-size: 1.2rem;
}

.footer-brand span {
  color: var(--green);
}

.footer-tagline {
  font-size: 0.8rem;
  color: var(--gray);
  margin-top: 0.4rem;
}

.footer-links {
  display: flex;
  gap: 2rem;
}

.footer-links a {
  font-size: 0.8rem;
  color: var(--gray);
  text-decoration: none;
  transition: color 0.3s ease;
}

.footer-links a:hover {
  color: var(--green);
}

.footer-copy {
  font-size: 0.75rem;
  color: rgba(255, 255, 255, 0.2);
}

.reveal {
  opacity: 0;
  transform: translateY(40px);
  transition: all 0.7s cubic-bezier(0.16, 1, 0.3, 1);
}

.reveal.visible {
  opacity: 1;
  transform: translateY(0);
}

.reveal-left {
  opacity: 0;
  transform: translateX(-40px);
  transition: all 0.7s cubic-bezier(0.16, 1, 0.3, 1);
}

.reveal-left.visible {
  opacity: 1;
  transform: translateX(0);
}

@keyframes fadeUp {
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes slideUp {
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes scrollPulse {
  0%,
  100% {
    opacity: 1;
    transform: scaleY(1);
  }

  50% {
    opacity: 0.4;
    transform: scaleY(0.7);
  }
}

@keyframes marqueeScroll {
  from {
    transform: translateX(0);
  }

  to {
    transform: translateX(-50%);
  }
}

@keyframes float {
  0%,
  100% {
    transform: translateY(0);
  }

  50% {
    transform: translateY(-10px);
  }
}

.orb {
  position: absolute;
  border-radius: 50%;
  pointer-events: none;
  background: radial-gradient(circle, rgba(16, 185, 129, 0.12) 0%, transparent 70%);
  animation: float 6s ease-in-out infinite;
}

::-webkit-scrollbar {
  width: 3px;
}

::-webkit-scrollbar-track {
  background: var(--black);
}

::-webkit-scrollbar-thumb {
  background: var(--green-dim);
  border-radius: 2px;
}

::selection {
  background: rgba(16, 185, 129, 0.3);
  color: var(--white);
}

.green {
  color: var(--green);
}

@media (max-width: 1100px) {
  .hero-container {
    grid-template-columns: 1fr;
    text-align: center;
  }

  .hero-content {
    max-width: 100%;
    display: flex;
    flex-direction: column;
    align-items: center;
  }

  .hero-sub {
    max-width: 600px;
  }

  .hero-eyebrow {
    justify-content: center;
  }

  .hero-visual {
    height: 400px;
    order: -1; /* Move sphere above text on tablets */
  }
}

@media (max-width: 768px) {
  .hero-visual {
    display: none; /* Hide sphere on mobile to save space */
  }

  nav .nav-links,
  nav .nav-cta {
    display: none;
  }

  nav {
    padding: 1rem 1.5rem;
  }

  .nav-logo {
    font-size: 1.2rem;
  }

  .section-inner {
    padding: 0 1.5rem;
  }

  .section-pad {
    padding-top: 5rem;
    padding-bottom: 5rem;
  }

  .problem-grid,
  .services-header,
  .about-layout,
  .contact-layout {
    grid-template-columns: 1fr;
    gap: 3.5rem;
  }

  .problem-visual {
    height: auto;
    display: flex;
    flex-direction: column;
    gap: 1.5rem;
    perspective: none;
  }

  .p-card {
    position: relative !important;
    top: auto !important;
    left: auto !important;
    width: 100% !important;
    margin: 0 !important;
    transform: none !important;
  }

  .steps-grid,
  .who-grid,
  .service-grid {
    grid-template-columns: 1fr;
  }

  .pricing-grid {
    grid-template-columns: 1fr;
  }

  .hero-headline {
    font-size: clamp(2.5rem, 10vw, 4rem);
  }

  .hero-counter {
    position: static;
    margin-top: 3rem;
    justify-content: center;
    gap: 2rem;
  }

  .hero-scroll {
    display: none;
  }

  footer {
    flex-direction: column;
    gap: 2.5rem;
    text-align: center;
    padding: 4rem 1.5rem;
  }

  .footer-links {
    flex-direction: column;
    gap: 1.2rem;
    align-items: center;
  }
}

@media (max-width: 480px) {
  .hero-actions {
    flex-direction: column;
    align-items: stretch;
  }

  .btn-primary {
    text-align: center;
  }

  .btn-ghost {
    justify-content: center;
  }

  .hero-headline {
    font-size: 2.8rem;
  }

  .counter-num {
    font-size: 1.8rem;
  }
}

/* ── Mobile hamburger toggle ── */
.mobile-menu-toggle {
  display: none;
  background: none;
  border: none;
  cursor: pointer;
  padding: 8px;
  z-index: 1001;
}

@media (max-width: 768px) {
  .mobile-menu-toggle {
    display: flex;
    align-items: center;
    justify-content: center;
  }
}

/* ── Mobile nav overlay + menu ── */
.mobile-nav-overlay {
  position: fixed;
  inset: 0;
  z-index: 998;
  background: rgba(0, 0, 0, 0.6);
  -webkit-backdrop-filter: blur(4px);
  backdrop-filter: blur(4px);
}

.mobile-nav-menu {
  position: fixed;
  top: 72px;
  left: 16px;
  right: 16px;
  z-index: 999;
  background: rgba(10, 10, 10, 0.97);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 16px;
  padding: 20px 8px;
  display: flex;
  flex-direction: column;
  gap: 2px;
  animation: slideDown 0.2s ease;
}

@keyframes slideDown {
  from { opacity: 0; transform: translateY(-10px); }
  to { opacity: 1; transform: translateY(0); }
}

.mobile-nav-menu a {
  color: #a1a1aa;
  text-decoration: none;
  font-size: 1rem;
  font-weight: 500;
  padding: 14px 20px;
  border-radius: 12px;
  transition: color 0.2s, background 0.2s;
}

.mobile-nav-menu a:hover,
.mobile-nav-menu a:active {
  color: #fff;
  background: rgba(255, 255, 255, 0.05);
}

.mobile-nav-cta {
  margin-top: 8px;
  background: var(--green) !important;
  color: #000 !important;
  text-align: center;
  border-radius: 999px !important;
  font-weight: 700 !important;
  padding: 14px 20px !important;
}

/* ============================
   LIGHT THEME OVERRIDES
   ============================ */
[data-theme="light"] {
  --black: #FFFFFF;
  --white: #1A1A1A;
  --green: #1E4A38;
  --green-dim: #6B9E72;
  --green-glow: rgba(30, 74, 56, 0.12);
