  inset: 0;
  background: 
    radial-gradient(at 0% 0%, hsla(160, 84%, 39%, 0.1) 0, transparent 50%), 
    radial-gradient(at 50% 0%, hsla(160, 84%, 39%, 0.05) 0, transparent 50%), 
    radial-gradient(at 100% 0%, hsla(160, 84%, 39%, 0.1) 0, transparent 50%),
    radial-gradient(at 50% 50%, hsla(160, 84%, 39%, 0.02) 0, transparent 50%);
