  color: var(--gray);
  max-width: 700px;
  line-height: 1.6;
  margin-bottom: 3.5rem;
  opacity: 0;
  transform: translateY(20px);
  animation: fadeUp 1s ease forwards 1.2s;
}

.hero-actions {
  display: flex;
  gap: 1.5rem;
  align-items: center;
  opacity: 0;
  transform: translateY(20px);
  animation: fadeUp 0.8s ease forwards 1.2s;
}

.btn-primary {
  background: var(--green);
  color: #000;
  padding: 1rem 2.2rem;
  border-radius: 2px;
  font-weight: 700;
  font-size: 0.85rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  text-decoration: none;
  display: inline-block;
  transition: all 0.3s ease;
  position: relative;
  overflow: hidden;
}

.btn-primary::before {
  content: '';
  position: absolute;
  inset: 0;
  background: rgba(255, 255, 255, 0.15);
  transform: translateX(-100%);
  transition: transform 0.4s ease;
}

.btn-primary:hover {
  transform: translateY(-2px);
  box-shadow: 0 16px 40px rgba(16, 185, 129, 0.35);
}

.btn-primary:hover::before {
  transform: translateX(0);
}

.btn-ghost {
  color: var(--white);
  font-size: 0.85rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  text-decoration: none;
  font-weight: 500;
  display: flex;
  align-items: center;
  gap: 0.6rem;
  transition: color 0.3s ease;
}

.btn-ghost span {
  font-size: 1.2rem;
  transition: transform 0.3s ease;
}

.btn-ghost:hover {
  color: var(--green);
}

.btn-ghost:hover span {
  transform: translateX(4px);
}

.hero-scroll {
  position: absolute;
  bottom: 3rem;
  left: 4rem;
  display: flex;
  align-items: center;
  gap: 1rem;
  opacity: 0;
  animation: fadeUp 0.8s ease forwards 1.5s;
}

.scroll-line {
  width: 1px;
  height: 60px;
  background: linear-gradient(to bottom, var(--green), transparent);
  animation: scrollPulse 2s ease infinite;
}

.scroll-text {
  font-size: 0.7rem;
  letter-spacing: 0.15em;
  color: var(--gray);
  text-transform: uppercase;
  writing-mode: vertical-lr;
}

.hero-counter {
  position: absolute;
  bottom: 3rem;
  right: 4rem;
  display: flex;
  gap: 3rem;
  opacity: 0;
  animation: fadeUp 0.8s ease forwards 1.6s;
}

.counter-item {
  text-align: right;
}

.counter-num {
