section {
  position: relative;
  z-index: 1;
}

.section-inner {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 4rem;
}

.section-pad {
  padding-top: 8rem;
  padding-bottom: 8rem;
}

.s-label {
  font-size: 0.7rem;
  font-weight: 500;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: var(--green);
  margin-bottom: 1.5rem;
  display: flex;
  align-items: center;
  gap: 1rem;
}

.s-label::before {
  content: '';
  display: block;
  width: 28px;
  height: 1px;
  background: var(--green);
}

.marquee-wrap {
  border-top: 1px solid rgba(255, 255, 255, 0.06);
  border-bottom: 1px solid rgba(255, 255, 255, 0.06);
  padding: 1.2rem 0;
  overflow: hidden;
  background: var(--dark);
}

.marquee-track {
  display: flex;
  gap: 0;
  width: max-content;
  animation: marqueeScroll 25s linear infinite;
}

.marquee-item {
  white-space: nowrap;
  padding: 0 3rem;
  font-size: 0.75rem;
  font-weight: 500;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--gray);
  display: flex;
  align-items: center;
  gap: 3rem;
}

.marquee-item::after {
