  overflow: hidden;
  transition: transform 0.6s cubic-bezier(0.22, 1, 0.36, 1), box-shadow 0.6s cubic-bezier(0.22, 1, 0.36, 1), border-color 0.4s ease;
  will-change: transform;
  cursor: default;
  z-index: 1;
