}

.p-card:nth-child(3) {
  top: 280px;
  left: 20px;
}

.p-card:nth-child(4) {
  top: 380px;
  left: 140px;
}

.p-card-icon {
  color: var(--green);
  font-size: 1.5rem;
  margin-bottom: 1rem;
}

.p-card-title {
  font-size: 0.9rem;
  font-weight: 600;
  color: var(--white);
  margin-bottom: 0.5rem;
  letter-spacing: -0.01em;
}

.p-card-body {
  font-size: 0.85rem;
  color: var(--gray);
  line-height: 1.6;
}

.problem-text h2 {
  font-family: 'Syne', sans-serif;
  font-weight: 800;
  font-size: clamp(2.5rem, 4.5vw, 4rem);
  line-height: 1.05;
  letter-spacing: -0.03em;
  margin-bottom: 2.5rem;
}

.problem-text h2 em {
  color: var(--green);
  font-style: normal;
}

.pain-list {
  list-style: none;
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.pain-list li {
  display: flex;
  gap: 1rem;
  align-items: flex-start;
