}

[data-theme="light"] .pricing-grid {
  background: rgba(30, 74, 56, 0.08);
}

[data-theme="light"] .price-card {
  background: #FFFFFF;
}

[data-theme="light"] .price-card.featured {
  background: linear-gradient(160deg, #f0f7f3 0%, #e8f0eb 100%);
  border-color: rgba(30, 74, 56, 0.4);
}

[data-theme="light"] .price-card.featured .price-card-glow {
  background: radial-gradient(circle at 50% 0%, rgba(30, 74, 56, 0.08) 0%, transparent 60%);
