}

[data-theme="light"] .price-card.featured .price-btn {
  color: #FFFFFF;
}

[data-theme="light"] .price-card.featured .price-btn:hover {
  background: #6B9E72;
  box-shadow: 0 8px 24px rgba(30, 74, 56, 0.25);
}

[data-theme="light"] .price-features li.dim {
  color: rgba(0, 0, 0, 0.25);
}

[data-theme="light"] .price-features li.dim::before {
  color: rgba(0, 0, 0, 0.2);
}

[data-theme="light"] .pricing-note {
  background: rgba(30, 74, 56, 0.04);
  border-color: rgba(30, 74, 56, 0.12);
}

/* Who */
[data-theme="light"] #who {
  background: #FFFFFF;
}

[data-theme="light"] .who-card {
  border-color: rgba(30, 74, 56, 0.12);
}

[data-theme="light"] .who-card::before {
  background: var(--green);
}

[data-theme="light"] .who-card:hover {
  border-color: var(--green);
}

[data-theme="light"] .who-title {
  color: #1A1A1A;
}

/* CTA band */
[data-theme="light"] #cta-band {
  background: linear-gradient(135deg, #f0f7f3 0%, #e4ede8 50%, #f0f7f3 100%);
  border-top-color: rgba(30, 74, 56, 0.12);
  border-bottom-color: rgba(30, 74, 56, 0.12);
}

[data-theme="light"] .cta-bg {
  background: radial-gradient(ellipse 70% 70% at 50% 50%, rgba(30, 74, 56, 0.06) 0%, transparent 70%);
}

[data-theme="light"] #cta-band h2 {
  color: #1A1A1A;
}

/* About */
[data-theme="light"] #about {
  background: #F9F7F4;
}

[data-theme="light"] .about-text h2 {
  color: #1A1A1A;
}

[data-theme="light"] .about-text .green-quote {
  color: #1A1A1A;
  border-left-color: var(--green);
}

[data-theme="light"] .value-item {
  background: #FFFFFF;
  border-color: rgba(30, 74, 56, 0.1);
}

[data-theme="light"] .value-item:hover {
  border-color: var(--green);
  box-shadow: 0 12px 30px rgba(30, 74, 56, 0.06);
}

[data-theme="light"] .value-title {
  color: #1A1A1A;
}

/* Contact */
[data-theme="light"] #contact {
  background: #FFFFFF;
}

[data-theme="light"] .contact-text h2 {
  color: #1A1A1A;
}

[data-theme="light"] .contact-item {
  border-color: rgba(30, 74, 56, 0.12);
  color: #1A1A1A;
}

[data-theme="light"] .contact-item:hover {
  border-color: rgba(30, 74, 56, 0.3);
  background: rgba(30, 74, 56, 0.03);
}

/* Form */
[data-theme="light"] .form-input,
[data-theme="light"] .form-select,
[data-theme="light"] .form-textarea {
  background: #FFFFFF;
  border-color: rgba(30, 74, 56, 0.15);
  color: #1A1A1A;
}

[data-theme="light"] .form-input:focus,
[data-theme="light"] .form-select:focus,
[data-theme="light"] .form-textarea:focus {
  border-color: var(--green);
  box-shadow: 0 0 0 3px rgba(30, 74, 56, 0.08);
}

[data-theme="light"] .form-input::placeholder,
[data-theme="light"] .form-textarea::placeholder {
  color: rgba(0, 0, 0, 0.35);
}

[data-theme="light"] .form-select option {
  background: #FFFFFF;
  color: #1A1A1A;
}

[data-theme="light"] .form-submit {
  color: #FFFFFF;
}

[data-theme="light"] .form-submit:hover {
  background: #6B9E72;
  box-shadow: 0 8px 24px rgba(30, 74, 56, 0.25);
}

/* Footer */
[data-theme="light"] footer {
  background: #F9F7F4;
  border-top-color: rgba(30, 74, 56, 0.1);
}

[data-theme="light"] .footer-brand {
  color: #1A1A1A;
}

[data-theme="light"] .footer-copy {
  color: #999999;
}

/* Scrollbar */
[data-theme="light"] ::-webkit-scrollbar-track {
  background: #FFFFFF;
}

[data-theme="light"] ::-webkit-scrollbar-thumb {
  background: rgba(30, 74, 56, 0.3);
}

[data-theme="light"] ::selection {
  background: rgba(30, 74, 56, 0.2);
  color: #1A1A1A;
}

/* Mobile nav */
[data-theme="light"] .mobile-nav-overlay {
  background: rgba(255, 255, 255, 0.6);
}

[data-theme="light"] .mobile-nav-menu {
  background: rgba(255, 255, 255, 0.97);
  border-color: rgba(30, 74, 56, 0.12);
}

[data-theme="light"] .mobile-nav-menu a {
  color: #666666;
}

[data-theme="light"] .mobile-nav-menu a:hover,
[data-theme="light"] .mobile-nav-menu a:active {
  color: #1A1A1A;
  background: rgba(30, 74, 56, 0.05);
}

[data-theme="light"] .mobile-nav-cta {
  color: #FFFFFF !important;
}

/* Mobile menu toggle icon — stroke override */
[data-theme="light"] .mobile-menu-toggle svg {
  stroke: #1A1A1A;
}

@import url('https://fonts.googleapis.com/css2?family=Syne:wght@400;500;600;700;800&family=Outfit:wght@300;400;500;600&display=swap');

:root {
  --black: #050505;
  --white: #f5f5f0;
  --green: #10b981;
  --green-dim: #059669;
  --green-glow: rgba(16, 185, 129, 0.15);
  --green-line: rgba(16, 185, 129, 0.3);
  --gray: #888880;
  --dark: #111110;
  --card: #0d0d0c;
}

html {
  scroll-behavior: smooth;
  font-size: 16px;
}

body {
  background: var(--black);
  color: var(--white);
  font-family: 'Outfit', sans-serif;
  font-weight: 400;
  line-height: 1.6;
  overflow-x: hidden;
  cursor: none;
}

body::before {
  content: '';
  position: fixed;
  inset: 0;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)' opacity='0.03'/%3E%3C/svg%3E");
  pointer-events: none;
  z-index: 0;
  opacity: 0.4;
}

.cursor {
  position: fixed;
  top: 0;
  left: 0;
  width: 10px;
  height: 10px;
  background: var(--green);
  border-radius: 50%;
  pointer-events: none;
  z-index: 9999;
  transform: translate(-50%, -50%);
  transition: transform 0.1s ease, width 0.3s ease, height 0.3s ease, background 0.3s ease;
  mix-blend-mode: normal;
}

.cursor-ring {
  position: fixed;
  top: 0;
  left: 0;
  width: 36px;
  height: 36px;
  border: 1px solid rgba(16, 185, 129, 0.5);
  border-radius: 50%;
  pointer-events: none;
  z-index: 9998;
  transform: translate(-50%, -50%);
  transition: transform 0.15s ease, width 0.3s ease, height 0.3s ease, opacity 0.3s ease;
}

.cursor.hover {
  width: 6px;
  height: 6px;
  background: var(--green);
}

.cursor-ring.hover {
  width: 56px;
  height: 56px;
  border-color: var(--green);
}

nav {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  z-index: 1000;
  padding: 1.5rem 4rem;
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: transparent;
  transition: background 0.4s ease, padding 0.4s ease;
}

nav.scrolled {
  background: rgba(5, 5, 5, 0.4);
  -webkit-backdrop-filter: blur(20px);
  backdrop-filter: blur(20px);
  padding: 1rem 4rem;
  border-bottom: 1px solid rgba(16, 185, 129, 0.1);
}

.nav-logo {
  font-family: 'Syne', sans-serif;
  font-weight: 800;
  font-size: 1.6rem;
  color: var(--white);
  text-decoration: none;
  letter-spacing: 0.05em;
}

.nav-logo span {
  color: var(--green);
}

.nav-links {
  display: flex;
  gap: 2.5rem;
  list-style: none;
}

.nav-links a {
  color: var(--gray);
  text-decoration: none;
  font-size: 0.85rem;
  font-weight: 500;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  transition: color 0.3s ease;
  position: relative;
}

.nav-links a::after {
  content: '';
  position: absolute;
  bottom: -3px;
  left: 0;
  right: 0;
  height: 1px;
  background: var(--green);
  transform: scaleX(0);
  transform-origin: left;
  transition: transform 0.3s ease;
}

.nav-links a:hover {
  color: var(--white);
}

.nav-links a:hover::after {
  transform: scaleX(1);
}

.nav-cta {
  background: var(--green);
  color: #000;
  padding: 0.6rem 1.4rem;
  border-radius: 2px;
  font-weight: 600;
  font-size: 0.8rem;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  text-decoration: none;
  transition: background 0.3s ease, transform 0.2s ease, box-shadow 0.3s ease;
}

.nav-cta:hover {
  background: #0ea371;
  transform: translateY(-1px);
  box-shadow: 0 8px 24px rgba(16, 185, 129, 0.3);
}

#hero {
  min-height: 100vh;
  display: flex;
  align-items: center;
  padding: 10rem 4rem 8rem;
  position: relative;
  overflow: hidden;
  background: var(--black);
}

.global-frost {
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 0;
}

.global-frost .luxury-mesh {
  position: absolute;
  inset: 0;
  background: 
    radial-gradient(at 0% 0%, hsla(160, 84%, 39%, 0.1) 0, transparent 50%), 
    radial-gradient(at 50% 0%, hsla(160, 84%, 39%, 0.05) 0, transparent 50%), 
    radial-gradient(at 100% 0%, hsla(160, 84%, 39%, 0.1) 0, transparent 50%),
    radial-gradient(at 50% 50%, hsla(160, 84%, 39%, 0.02) 0, transparent 50%);
  pointer-events: none;
  z-index: 1;
}

.global-frost .hero-grid {
  position: absolute;
  inset: 0;
  pointer-events: none;
  background-image: radial-gradient(rgba(16, 185, 129, 0.1) 1px, transparent 1px);
  background-size: 40px 40px;
  -webkit-mask-image: radial-gradient(ellipse at center, black 20%, transparent 80%);
  mask-image: radial-gradient(ellipse at center, black 20%, transparent 80%);
