  border-color: rgba(16, 185, 129, 0.3);
  color: var(--white);
  background: rgba(16, 185, 129, 0.04);
}

.contact-item .ci-label {
  font-size: 0.7rem;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--green);
  display: block;
  margin-bottom: 0.2rem;
}

.contact-form {
  display: flex;
  flex-direction: column;
  gap: 1.2rem;
}

.form-group {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.form-label {
  font-size: 0.72rem;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--gray);
  font-weight: 500;
}

.form-input,
.form-select,
.form-textarea {
  background: var(--card);
  border: 1px solid rgba(255, 255, 255, 0.08);
  color: var(--white);
  padding: 0.9rem 1.1rem;
  border-radius: 2px;
  font-family: 'Outfit', sans-serif;
  font-size: 0.9rem;
  transition: border-color 0.3s ease, box-shadow 0.3s ease;
  outline: none;
  width: 100%;
}

.form-input:focus,
.form-select:focus,
.form-textarea:focus {
  border-color: rgba(16, 185, 129, 0.5);
  box-shadow: 0 0 0 3px rgba(16, 185, 129, 0.08);
}

.form-select option {
  background: var(--dark);
}

.form-textarea {
  resize: vertical;
  min-height: 100px;
}

.form-submit {
  background: var(--green);
  color: #000;
  border: none;
  padding: 1rem 2rem;
  font-family: 'Outfit', sans-serif;
  font-size: 0.85rem;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  border-radius: 2px;
  cursor: none;
  transition: all 0.3s ease;
}

.form-submit:hover {
  background: #0ea371;
  box-shadow: 0 8px 24px rgba(16, 185, 129, 0.3);
  transform: translateY(-1px);
}

footer {
  background: var(--dark);
  border-top: 1px solid rgba(255, 255, 255, 0.05);
  padding: 4rem;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.footer-brand {
  font-family: 'Syne', sans-serif;
  font-weight: 800;
  font-size: 1.2rem;
}

.footer-brand span {
  color: var(--green);
}

.footer-tagline {
  font-size: 0.8rem;
  color: var(--gray);
  margin-top: 0.4rem;
}

.footer-links {
  display: flex;
  gap: 2rem;
}

.footer-links a {
  font-size: 0.8rem;
  color: var(--gray);
  text-decoration: none;
  transition: color 0.3s ease;
}

.footer-links a:hover {
  color: var(--green);
}

.footer-copy {
  font-size: 0.75rem;
  color: rgba(255, 255, 255, 0.2);
}

.reveal {
  opacity: 0;
  transform: translateY(40px);
  transition: all 0.7s cubic-bezier(0.16, 1, 0.3, 1);
}

.reveal.visible {
  opacity: 1;
  transform: translateY(0);
}

.reveal-left {
  opacity: 0;
  transform: translateX(-40px);
  transition: all 0.7s cubic-bezier(0.16, 1, 0.3, 1);
}

.reveal-left.visible {
  opacity: 1;
  transform: translateX(0);
}

@keyframes fadeUp {
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes slideUp {
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes scrollPulse {
  0%,
  100% {
    opacity: 1;
    transform: scaleY(1);
  }

  50% {
    opacity: 0.4;
    transform: scaleY(0.7);
  }
}

@keyframes marqueeScroll {
  from {
    transform: translateX(0);
  }

  to {
    transform: translateX(-50%);
  }
}

@keyframes float {
  0%,
  100% {
    transform: translateY(0);
  }

  50% {
    transform: translateY(-10px);
  }
}

.orb {
  position: absolute;
  border-radius: 50%;
  pointer-events: none;
  background: radial-gradient(circle, rgba(16, 185, 129, 0.12) 0%, transparent 70%);
  animation: float 6s ease-in-out infinite;
}

::-webkit-scrollbar {
  width: 3px;
}

::-webkit-scrollbar-track {
  background: var(--black);
}

::-webkit-scrollbar-thumb {
  background: var(--green-dim);
  border-radius: 2px;
}

::selection {
  background: rgba(16, 185, 129, 0.3);
  color: var(--white);
}

.green {
  color: var(--green);
}

@media (max-width: 1100px) {
  .hero-container {
    grid-template-columns: 1fr;
    text-align: center;
  }

  .hero-content {
    max-width: 100%;
    display: flex;
    flex-direction: column;
    align-items: center;
  }

  .hero-sub {
    max-width: 600px;
  }

  .hero-eyebrow {
    justify-content: center;
  }

  .hero-visual {
    height: 400px;
    order: -1; /* Move sphere above text on tablets */
  }
}

@media (max-width: 768px) {
  .hero-visual {
    display: none; /* Hide sphere on mobile to save space */
  }

  nav .nav-links,
  nav .nav-cta {
    display: none;
  }

  nav {
    padding: 1rem 1.5rem;
  }

  .nav-logo {
    font-size: 1.2rem;
  }

  .section-inner {
    padding: 0 1.5rem;
  }

  .section-pad {
    padding-top: 5rem;
    padding-bottom: 5rem;
  }

  .problem-grid,
  .services-header,
  .about-layout,
  .contact-layout {
    grid-template-columns: 1fr;
    gap: 3.5rem;
  }

  .problem-visual {
    height: auto;
    display: flex;
    flex-direction: column;
    gap: 1.5rem;
    perspective: none;
  }

  .p-card {
    position: relative !important;
    top: auto !important;
    left: auto !important;
    width: 100% !important;
    margin: 0 !important;
    transform: none !important;
  }

  .steps-grid,
  .who-grid,
  .service-grid {
    grid-template-columns: 1fr;
  }

  .pricing-grid {
    grid-template-columns: 1fr;
  }

  .hero-headline {
    font-size: clamp(2.5rem, 10vw, 4rem);
  }

  .hero-counter {
    position: static;
    margin-top: 3rem;
    justify-content: center;
    gap: 2rem;
  }

  .hero-scroll {
    display: none;
  }

  footer {
    flex-direction: column;
    gap: 2.5rem;
    text-align: center;
    padding: 4rem 1.5rem;
  }

  .footer-links {
    flex-direction: column;
    gap: 1.2rem;
    align-items: center;
  }
}

@media (max-width: 480px) {
  .hero-actions {
    flex-direction: column;
    align-items: stretch;
  }

  .btn-primary {
    text-align: center;
  }

  .btn-ghost {
    justify-content: center;
  }

  .hero-headline {
    font-size: 2.8rem;
  }

  .counter-num {
    font-size: 1.8rem;
  }
}

/* ── Mobile hamburger toggle ── */
.mobile-menu-toggle {
  display: none;
  background: none;
  border: none;
  cursor: pointer;
  padding: 8px;
  z-index: 1001;
}

@media (max-width: 768px) {
  .mobile-menu-toggle {
    display: flex;
    align-items: center;
    justify-content: center;
  }
}

/* ── Mobile nav overlay + menu ── */
.mobile-nav-overlay {
  position: fixed;
  inset: 0;
  z-index: 998;
  background: rgba(0, 0, 0, 0.6);
  -webkit-backdrop-filter: blur(4px);
  backdrop-filter: blur(4px);
}

.mobile-nav-menu {
  position: fixed;
  top: 72px;
  left: 16px;
  right: 16px;
  z-index: 999;
  background: rgba(10, 10, 10, 0.97);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 16px;
  padding: 20px 8px;
  display: flex;
  flex-direction: column;
  gap: 2px;
  animation: slideDown 0.2s ease;
}

@keyframes slideDown {
  from { opacity: 0; transform: translateY(-10px); }
  to { opacity: 1; transform: translateY(0); }
}

.mobile-nav-menu a {
  color: #a1a1aa;
  text-decoration: none;
  font-size: 1rem;
  font-weight: 500;
  padding: 14px 20px;
  border-radius: 12px;
  transition: color 0.2s, background 0.2s;
}

.mobile-nav-menu a:hover,
.mobile-nav-menu a:active {
  color: #fff;
  background: rgba(255, 255, 255, 0.05);
}

.mobile-nav-cta {
  margin-top: 8px;
  background: var(--green) !important;
  color: #000 !important;
  text-align: center;
  border-radius: 999px !important;
  font-weight: 700 !important;
  padding: 14px 20px !important;
}

/* ============================
   LIGHT THEME OVERRIDES
   ============================ */
[data-theme="light"] {
  --black: #FFFFFF;
  --white: #1A1A1A;
  --green: #1E4A38;
  --green-dim: #6B9E72;
  --green-glow: rgba(30, 74, 56, 0.12);
  --green-line: rgba(30, 74, 56, 0.25);
  --gray: #666666;
  --dark: #F9F7F4;
  --card: #FFFFFF;
  --theme-toggle-border: rgba(30, 74, 56, 0.2);
}

/* Body & background */
[data-theme="light"] body {
  background: #FFFFFF;
  color: #1A1A1A;
}

[data-theme="light"] body::before {
  opacity: 0.15;
}

/* Custom cursor */
[data-theme="light"] .cursor {
  mix-blend-mode: normal;
}

/* Nav */
[data-theme="light"] nav.scrolled {
  background: rgba(255, 255, 255, 0.4);
  border-bottom-color: rgba(30, 74, 56, 0.12);
}

[data-theme="light"] .nav-links a {
  color: #7A7A7A;
}

[data-theme="light"] .nav-links a:hover {
  color: #1A1A1A;
}

[data-theme="light"] .nav-cta {
  color: #FFFFFF;
}

[data-theme="light"] .nav-cta:hover {
  background: #6B9E72;
  box-shadow: 0 8px 24px rgba(30, 74, 56, 0.25);
}

/* Hero */
[data-theme="light"] #hero {
  background: linear-gradient(135deg, #FFFFFF 0%, #F5F0E8 100%);
}

[data-theme="light"] .hero-bg {
  background: radial-gradient(ellipse 60% 60% at 70% 50%, rgba(30, 74, 56, 0.05) 0%, transparent 70%);
}

[data-theme="light"] .hero-grid {
  background-image:
    linear-gradient(rgba(30, 74, 56, 0.03) 1px, transparent 1px),
    linear-gradient(90deg, rgba(30, 74, 56, 0.03) 1px, transparent 1px);
}

[data-theme="light"] .hero-headline .line span {
  color: #1A1A1A;
}

[data-theme="light"] .hero-headline .line:nth-child(3) span {
  color: var(--green);
}

[data-theme="light"] .hero-sub {
  color: #666666;
}

[data-theme="light"] .btn-primary {
  color: #FFFFFF;
}

[data-theme="light"] .btn-primary:hover {
  box-shadow: 0 16px 40px rgba(30, 74, 56, 0.3);
}

[data-theme="light"] .btn-ghost {
  color: #1A1A1A;
}

[data-theme="light"] .counter-num {
  color: #1A1A1A;
}

[data-theme="light"] .counter-label {
  color: #888888;
}

/* Orb */
[data-theme="light"] .orb {
  background: radial-gradient(circle, rgba(30, 74, 56, 0.06) 0%, transparent 70%);
}

/* Marquee */
[data-theme="light"] .marquee-wrap {
  border-top-color: rgba(30, 74, 56, 0.08);
  border-bottom-color: rgba(30, 74, 56, 0.08);
  background: #F9F7F4;
}

/* Problem cards */
[data-theme="light"] .p-card {
  background: #FFFFFF;
  border-color: rgba(30, 74, 56, 0.15);
}

[data-theme="light"] .p-card:nth-child(2) {
  border-color: rgba(30, 74, 56, 0.25);
}

[data-theme="light"] .p-card-title {
  color: #1A1A1A;
}

[data-theme="light"] .problem-text h2 {
  color: #1A1A1A;
}

/* Pain list */
[data-theme="light"] .pain-list li {
  background: #FFFFFF;
  border-color: rgba(30, 74, 56, 0.1);
  color: #666666;
}

/* Steps */
[data-theme="light"] #how {
  background: #F9F7F4;
}

[data-theme="light"] .step-card {
  background: #FFFFFF;
}

[data-theme="light"] .step-card:hover {
  background: #FAFAF8;
}

[data-theme="light"] .step-num {
  color: rgba(30, 74, 56, 0.15);
}

[data-theme="light"] .step-card:hover .step-num {
  color: rgba(30, 74, 56, 0.3);
}

[data-theme="light"] .step-title {
  color: #1A1A1A;
}

[data-theme="light"] .step-card::before {
  background: linear-gradient(90deg, var(--green), transparent);
}

/* Services */
[data-theme="light"] #services {
  background: #FFFFFF;
}

[data-theme="light"] .service-grid {
  background: rgba(30, 74, 56, 0.08);
}

[data-theme="light"] .service-item {
  background: #FFFFFF;
}

[data-theme="light"] .service-bg-glow {
  background: radial-gradient(circle at 0% 100%, rgba(30, 74, 56, 0.06) 0%, transparent 60%);
}

[data-theme="light"] .service-icon {
  border-color: rgba(30, 74, 56, 0.25);
}

[data-theme="light"] .service-item:hover .service-icon {
  background: var(--green);
  border-color: var(--green);
}

[data-theme="light"] .service-name {
  color: #1A1A1A;
}

/* Pricing */
[data-theme="light"] #pricing {
  background: #F9F7F4;
}

[data-theme="light"] .pricing-grid {
  background: rgba(30, 74, 56, 0.08);
}

[data-theme="light"] .price-card {
  background: #FFFFFF;
}

[data-theme="light"] .price-card.featured {
  background: linear-gradient(160deg, #f0f7f3 0%, #e8f0eb 100%);
  border-color: rgba(30, 74, 56, 0.4);
}

[data-theme="light"] .price-card.featured .price-card-glow {
  background: radial-gradient(circle at 50% 0%, rgba(30, 74, 56, 0.08) 0%, transparent 60%);
}

[data-theme="light"] .popular-badge {
  background: var(--green);
  color: #FFFFFF;
}

[data-theme="light"] .price-name {
  color: #1A1A1A;
}

[data-theme="light"] .price-num {
  color: #1A1A1A;
}

[data-theme="light"] .price-amount {
  border-bottom-color: rgba(30, 74, 56, 0.1);
}

[data-theme="light"] .price-btn {
  border-color: rgba(30, 74, 56, 0.2);
  color: #1A1A1A;
}

[data-theme="light"] .price-btn:hover {
  border-color: var(--green);
  color: var(--green);
}

[data-theme="light"] .price-card.featured .price-btn {
  color: #FFFFFF;
}

[data-theme="light"] .price-card.featured .price-btn:hover {
  background: #6B9E72;
  box-shadow: 0 8px 24px rgba(30, 74, 56, 0.25);
}

[data-theme="light"] .price-features li.dim {
  color: rgba(0, 0, 0, 0.25);
}

[data-theme="light"] .price-features li.dim::before {
  color: rgba(0, 0, 0, 0.2);
}

[data-theme="light"] .pricing-note {
  background: rgba(30, 74, 56, 0.04);
  border-color: rgba(30, 74, 56, 0.12);
}

/* Who */
[data-theme="light"] #who {
  background: #FFFFFF;
}

[data-theme="light"] .who-card {
  border-color: rgba(30, 74, 56, 0.12);
}

[data-theme="light"] .who-card::before {
  background: var(--green);
}

[data-theme="light"] .who-card:hover {
  border-color: var(--green);
}

[data-theme="light"] .who-title {
  color: #1A1A1A;
}

/* CTA band */
[data-theme="light"] #cta-band {
  background: linear-gradient(135deg, #f0f7f3 0%, #e4ede8 50%, #f0f7f3 100%);
  border-top-color: rgba(30, 74, 56, 0.12);
  border-bottom-color: rgba(30, 74, 56, 0.12);
}

[data-theme="light"] .cta-bg {
  background: radial-gradient(ellipse 70% 70% at 50% 50%, rgba(30, 74, 56, 0.06) 0%, transparent 70%);
}

[data-theme="light"] #cta-band h2 {
  color: #1A1A1A;
}

/* About */
[data-theme="light"] #about {
  background: #F9F7F4;
}

[data-theme="light"] .about-text h2 {
  color: #1A1A1A;
}

[data-theme="light"] .about-text .green-quote {
  color: #1A1A1A;
  border-left-color: var(--green);
}

[data-theme="light"] .value-item {
  background: #FFFFFF;
  border-color: rgba(30, 74, 56, 0.1);
}

[data-theme="light"] .value-item:hover {
  border-color: var(--green);
  box-shadow: 0 12px 30px rgba(30, 74, 56, 0.06);
}

[data-theme="light"] .value-title {
  color: #1A1A1A;
}

/* Contact */
[data-theme="light"] #contact {
  background: #FFFFFF;
}

[data-theme="light"] .contact-text h2 {
  color: #1A1A1A;
}

[data-theme="light"] .contact-item {
  border-color: rgba(30, 74, 56, 0.12);
  color: #1A1A1A;
}

[data-theme="light"] .contact-item:hover {
  border-color: rgba(30, 74, 56, 0.3);
  background: rgba(30, 74, 56, 0.03);
}

/* Form */
[data-theme="light"] .form-input,
[data-theme="light"] .form-select,
[data-theme="light"] .form-textarea {
  background: #FFFFFF;
  border-color: rgba(30, 74, 56, 0.15);
  color: #1A1A1A;
}

[data-theme="light"] .form-input:focus,
[data-theme="light"] .form-select:focus,
[data-theme="light"] .form-textarea:focus {
  border-color: var(--green);
  box-shadow: 0 0 0 3px rgba(30, 74, 56, 0.08);
}

[data-theme="light"] .form-input::placeholder,
[data-theme="light"] .form-textarea::placeholder {
  color: rgba(0, 0, 0, 0.35);
}

[data-theme="light"] .form-select option {
  background: #FFFFFF;
  color: #1A1A1A;
}

[data-theme="light"] .form-submit {
  color: #FFFFFF;
}

[data-theme="light"] .form-submit:hover {
  background: #6B9E72;
  box-shadow: 0 8px 24px rgba(30, 74, 56, 0.25);
}

/* Footer */
[data-theme="light"] footer {
  background: #F9F7F4;
  border-top-color: rgba(30, 74, 56, 0.1);
}

[data-theme="light"] .footer-brand {
  color: #1A1A1A;
}

[data-theme="light"] .footer-copy {
  color: #999999;
}

/* Scrollbar */
[data-theme="light"] ::-webkit-scrollbar-track {
  background: #FFFFFF;
}

[data-theme="light"] ::-webkit-scrollbar-thumb {
  background: rgba(30, 74, 56, 0.3);
}

[data-theme="light"] ::selection {
  background: rgba(30, 74, 56, 0.2);
  color: #1A1A1A;
}

/* Mobile nav */
[data-theme="light"] .mobile-nav-overlay {
  background: rgba(255, 255, 255, 0.6);
}

[data-theme="light"] .mobile-nav-menu {
  background: rgba(255, 255, 255, 0.97);
  border-color: rgba(30, 74, 56, 0.12);
}

[data-theme="light"] .mobile-nav-menu a {
  color: #666666;
}

[data-theme="light"] .mobile-nav-menu a:hover,
[data-theme="light"] .mobile-nav-menu a:active {
  color: #1A1A1A;
  background: rgba(30, 74, 56, 0.05);
}

[data-theme="light"] .mobile-nav-cta {
  color: #FFFFFF !important;
}

/* Mobile menu toggle icon — stroke override */
[data-theme="light"] .mobile-menu-toggle svg {
  stroke: #1A1A1A;
}

@import url('https://fonts.googleapis.com/css2?family=Syne:wght@400;500;600;700;800&family=Outfit:wght@300;400;500;600&display=swap');

:root {
  --black: #050505;
  --white: #f5f5f0;
  --green: #10b981;
  --green-dim: #059669;
  --green-glow: rgba(16, 185, 129, 0.15);
  --green-line: rgba(16, 185, 129, 0.3);
  --gray: #888880;
  --dark: #111110;
  --card: #0d0d0c;
}

html {
  scroll-behavior: smooth;
  font-size: 16px;
}

body {
  background: var(--black);
  color: var(--white);
  font-family: 'Outfit', sans-serif;
  font-weight: 400;
  line-height: 1.6;
  overflow-x: hidden;
  cursor: none;
}

body::before {
  content: '';
  position: fixed;
  inset: 0;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)' opacity='0.03'/%3E%3C/svg%3E");
  pointer-events: none;
  z-index: 0;
  opacity: 0.4;
}

.cursor {
  position: fixed;
  top: 0;
  left: 0;
  width: 10px;
  height: 10px;
  background: var(--green);
  border-radius: 50%;
  pointer-events: none;
  z-index: 9999;
  transform: translate(-50%, -50%);
  transition: transform 0.1s ease, width 0.3s ease, height 0.3s ease, background 0.3s ease;
  mix-blend-mode: normal;
}

.cursor-ring {
  position: fixed;
  top: 0;
  left: 0;
  width: 36px;
  height: 36px;
  border: 1px solid rgba(16, 185, 129, 0.5);
  border-radius: 50%;
  pointer-events: none;
  z-index: 9998;
  transform: translate(-50%, -50%);
  transition: transform 0.15s ease, width 0.3s ease, height 0.3s ease, opacity 0.3s ease;
}

.cursor.hover {
  width: 6px;
  height: 6px;
  background: var(--green);
}

.cursor-ring.hover {
  width: 56px;
  height: 56px;
  border-color: var(--green);
}

nav {
  position: fixed;
  top: 0;
  left: 0;
