.btn-primary {
  background: var(--green);
  color: #000;
  padding: 1rem 2.2rem;
  border-radius: 2px;
  font-weight: 700;
  font-size: 0.85rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
