.orb {
  position: absolute;
  border-radius: 50%;
  pointer-events: none;
  background: radial-gradient(circle, rgba(16, 185, 129, 0.12) 0%, transparent 70%);
  animation: float 6s ease-in-out infinite;
}

::-webkit-scrollbar {
  width: 3px;
}

::-webkit-scrollbar-track {
  background: var(--black);
}

::-webkit-scrollbar-thumb {
  background: var(--green-dim);
  border-radius: 2px;
}

::selection {
  background: rgba(16, 185, 129, 0.3);
  color: var(--white);
}

.green {
  color: var(--green);
}

@media (max-width: 1100px) {
  .hero-container {
    grid-template-columns: 1fr;
    text-align: center;
  }

  .hero-content {
    max-width: 100%;
    display: flex;
    flex-direction: column;
    align-items: center;
  }

  .hero-sub {
    max-width: 600px;
  }

  .hero-eyebrow {
    justify-content: center;
  }

  .hero-visual {
    height: 400px;
    order: -1; /* Move sphere above text on tablets */
  }
}

@media (max-width: 768px) {
  .hero-visual {
    display: none; /* Hide sphere on mobile to save space */
  }

  nav .nav-links,
  nav .nav-cta {
    display: none;
  }

  nav {
    padding: 1rem 1.5rem;
  }

  .nav-logo {
    font-size: 1.2rem;
  }

  .section-inner {
    padding: 0 1.5rem;
  }

  .section-pad {
    padding-top: 5rem;
    padding-bottom: 5rem;
  }

  .problem-grid,
  .services-header,
  .about-layout,
  .contact-layout {
    grid-template-columns: 1fr;
    gap: 3.5rem;
  }

  .problem-visual {
    height: auto;
    display: flex;
    flex-direction: column;
    gap: 1.5rem;
    perspective: none;
  }

  .p-card {
    position: relative !important;
    top: auto !important;
    left: auto !important;
    width: 100% !important;
    margin: 0 !important;
    transform: none !important;
  }

  .steps-grid,
  .who-grid,
  .service-grid {
    grid-template-columns: 1fr;
  }

  .pricing-grid {
    grid-template-columns: 1fr;
  }

  .hero-headline {
    font-size: clamp(2.5rem, 10vw, 4rem);
  }

  .hero-counter {
    position: static;
    margin-top: 3rem;
    justify-content: center;
    gap: 2rem;
  }

  .hero-scroll {
    display: none;
  }

  footer {
    flex-direction: column;
    gap: 2.5rem;
    text-align: center;
    padding: 4rem 1.5rem;
  }

  .footer-links {
    flex-direction: column;
    gap: 1.2rem;
    align-items: center;
  }
}

@media (max-width: 480px) {
  .hero-actions {
    flex-direction: column;
    align-items: stretch;
  }

  .btn-primary {
    text-align: center;
  }

  .btn-ghost {
    justify-content: center;
  }

  .hero-headline {
    font-size: 2.8rem;
  }

  .counter-num {
    font-size: 1.8rem;
  }
}

